  3	namespace App\Providers;
  4	
  5	use Illuminate\Cache\RateLimiting\Limit;
  6	use Illuminate\Http\Request;
  7	use Illuminate\Support\Facades\RateLimiter;
  8	use Illuminate\Support\Facades\Route;
  9	use Illuminate\Support\ServiceProvider;
 10	
 11	class AppServiceProvider extends ServiceProvider
 12	{
 13	    /**
 14	     * Register any application services.
 15	     */
 16	    public function register(): void
 17	    {
 18	        $this->registerModuleProviders();
 19	    }
 20	
 21	    /**
 22	     * Bootstrap any application services.
 23	     */
 24	    public function boot(): void
 25	    {
 26	        $this->loadModuleRoutes();
 27	        $this->loadModuleMigrations();
 28	        $this->registerRateLimiters();
 29	    }
 30	
 31	    /**
 32	     * Auto-discover and register ServiceProviders from each module's Providers directory.
 33	     */
 34	    private function registerModuleProviders(): void
 35	    {
 36	        $modulesPath = app_path('Modules');
 37	        if (! is_dir($modulesPath)) {
 38	            return;
 39	        }
 40	
 41	        foreach (glob("{$modulesPath}/*/Providers/*ServiceProvider.php") as $providerFile) {
 42	            // Derive FQCN: app/Modules/Vendor/Providers/VendorServiceProvider.php
 43	            // → App\Modules\Vendor\Providers\VendorServiceProvider
 44	            $relativePath = str_replace(app_path().DIRECTORY_SEPARATOR, '', $providerFile);
 45	            $className = 'App\\'.str_replace(
 46	                [DIRECTORY_SEPARATOR, '.php'],
 47	                ['\\', ''],
 48	                $relativePath
 49	            );
 50	
 51	            if (class_exists($className)) {
 52	                $this->app->register($className);
 53	            }
 54	        }
 55	    }
 56	
 57	    /**
 58	     * Auto-load route files from each module's Routes directory.
 59	     */
 60	    private function loadModuleRoutes(): void
 61	    {
 62	        $modulesPath = app_path('Modules');
 63	        if (! is_dir($modulesPath)) {
 64	            return;
 65	        }
 66	
 67	        foreach (glob("{$modulesPath}/*/Routes/api.php") as $routeFile) {
 68	            Route::prefix('api/v5')
 69	                ->middleware(['api', 'auth:sanctum', 'password.change', 'active.tab', 'throttle:api.write'])
 70	                ->group($routeFile);
 71	        }
 72	    }
 73	
 74	    /**
 75	     * Auto-load migration directories from each module's Database/Migrations directory.
 76	     */
 77	    private function loadModuleMigrations(): void
 78	    {
 79	        $modulesPath = app_path('Modules');
 80	        if (! is_dir($modulesPath)) {
 81	            return;
 82	        }
 83	
 84	        foreach (glob("{$modulesPath}/*/Database/Migrations", GLOB_ONLYDIR) as $migrationDir) {
 85	            $this->loadMigrationsFrom($migrationDir);
 86	        }
 87	    }
 88	
 89	    /**
 90	     * Register rate limiters for auth and API routes.
 91	     */
 92	    private function registerRateLimiters(): void
 93	    {
 94	        RateLimiter::for('auth.login', function (Request $request): Limit {
 95	            $username = strtolower(trim((string) $request->input('username', '')));
 96	            $key = sprintf('%s|%s', $request->ip(), $username);
 97	
 98	            return Limit::perMinute(5)->by($key);
 99	        });
100	
101	        RateLimiter::for('auth.refresh', function (Request $request): Limit {
102	            $userAgentHash = substr(sha1((string) $request->userAgent()), 0, 16);
103	            $key = sprintf('%s|%s', $request->ip(), $userAgentHash);
104	
105	            return Limit::perMinute(10)->by($key);
106	        });
107	
108	        RateLimiter::for('api.write', function (Request $request): Limit {
109	            if (in_array($request->method(), ['GET', 'HEAD', 'OPTIONS'], true)) {
110	                return Limit::none();
111	            }
112	
113	            if ($request->is('api/v5/auth/login') || $request->is('api/v5/auth/refresh')) {
114	                return Limit::none();
115	            }
116	
117	            $userId = $request->user()?->id;
118	            $principal = $userId !== null ? 'u:'.(int) $userId : 'g';
119	            $userAgentHash = substr(sha1((string) $request->userAgent()), 0, 16);
120	            $key = sprintf('%s|%s|%s', $principal, $request->ip(), $userAgentHash);
121	
122	            return Limit::perMinute(30)
123	                ->by($key)
124	                ->response(fn (): \Illuminate\Http\JsonResponse => response()->json([
125	                    'message' => 'Bạn thao tác quá nhanh. Vui lòng thử lại sau ít phút.',
126	                    'code' => 'TOO_MANY_REQUESTS',
127	                ], 429));
128	        });
129	
130	        RateLimiter::for('api.write.heavy', function (Request $request): Limit {
131	            $userId = $request->user()?->id;
132	            $principal = $userId !== null ? 'u:'.(int) $userId : 'g';
133	            $userAgentHash = substr(sha1((string) $request->userAgent()), 0, 16);
134	            $key = sprintf('%s|%s|%s', $principal, $request->ip(), $userAgentHash);
135	
136	            return Limit::perMinute(10)
137	                ->by($key)
138	                ->response(fn (): \Illuminate\Http\JsonResponse => response()->json([
139	                    'message' => 'Bạn đã vượt giới hạn thao tác nặng. Vui lòng thử lại sau.',
140	                    'code' => 'TOO_MANY_REQUESTS_HEAVY',
141	                ], 429));
142	        });
143	    }
144	}

