  1	import { create } from 'zustand';
  2	import type { AuthLoginPayload, AuthLoginResult, AuthUser } from '../../types';
  3	import {
  4	  fetchAuthBootstrap,
  5	  fetchCurrentUser,
  6	  login as loginRequest,
  7	  logout as logoutRequest,
  8	} from '../../services/v5Api';
  9	
 10	interface AuthState {
 11	  user: AuthUser | null;
 12	  isAuthLoading: boolean;
 13	  isLoginLoading: boolean;
 14	  passwordChangeRequired: boolean;
 15	
 16	  bootstrapAuth: () => Promise<void>;
 17	  login: (payload: AuthLoginPayload) => Promise<AuthLoginResult>;
 18	  logout: () => Promise<void>;
 19	  refreshCurrentUser: () => Promise<AuthUser>;
 20	  setUser: (user: AuthUser | null) => void;
 21	  clearAuth: () => void;
 22	  setPasswordChangeRequired: (value: boolean) => void;
 23	}
 24	
 25	const resolvePasswordChangeRequired = (user: AuthUser | null | undefined): boolean =>
 26	  Boolean(user?.password_change_required);
 27	
 28	export const useAuthStore = create<AuthState>((set) => ({
 29	  user: null,
 30	  isAuthLoading: true,
 31	  isLoginLoading: false,
 32	  passwordChangeRequired: false,
 33	
 34	  bootstrapAuth: async () => {
 35	    set({ isAuthLoading: true });
 36	    try {
 37	      const bootstrap = await fetchAuthBootstrap();
 38	      set({
 39	        user: bootstrap.user,
 40	        passwordChangeRequired: resolvePasswordChangeRequired(bootstrap.user),
 41	      });
 42	    } catch (error) {
 43	      const message = error instanceof Error ? error.message : '';
 44	      if (message === 'PASSWORD_CHANGE_REQUIRED') {
 45	        try {
 46	          const currentUser = await fetchCurrentUser();
 47	          set({
 48	            user: currentUser,
 49	            passwordChangeRequired: Boolean(currentUser.password_change_required ?? true),
 50	          });
 51	          return;
 52	        } catch {
 53	          // Fall through to clearing auth state below.
 54	        }
 55	      }
 56	
 57	      set({
 58	        user: null,
 59	        passwordChangeRequired: false,
 60	      });
 61	    } finally {
 62	      set({ isAuthLoading: false });
 63	    }
 64	  },
 65	
 66	  login: async (payload) => {
 67	    set({ isLoginLoading: true });
 68	    try {
 69	      const session = await loginRequest(payload);
 70	      const passwordChangeRequired = Boolean(
 71	        session.password_change_required || session.user.password_change_required
 72	      );
 73	
 74	      set({
 75	        user: session.user,
 76	        passwordChangeRequired,
 77	      });
 78	
 79	      return session;
 80	    } finally {
 81	      set({ isLoginLoading: false });
 82	    }
 83	  },
 84	
 85	  logout: async () => {
 86	    try {
 87	      await logoutRequest();
 88	    } catch {
 89	      // Ignore logout request failures and clear local auth state anyway.
 90	    } finally {
 91	      set({
 92	        user: null,
 93	        isAuthLoading: false,
 94	        isLoginLoading: false,
 95	        passwordChangeRequired: false,
 96	      });
 97	    }
 98	  },
 99	
100	  refreshCurrentUser: async () => {
101	    const currentUser = await fetchCurrentUser();
102	    set({
103	      user: currentUser,
104	      passwordChangeRequired: resolvePasswordChangeRequired(currentUser),
105	    });
106	    return currentUser;
107	  },
108	
109	  setUser: (user) =>
110	    set({
111	      user,
112	      passwordChangeRequired: resolvePasswordChangeRequired(user),
113	    }),
114	
115	  clearAuth: () =>
116	    set({
117	      user: null,
118	      isAuthLoading: false,
119	      isLoginLoading: false,
120	      passwordChangeRequired: false,
121	    }),
122	
123	  setPasswordChangeRequired: (value) => set({ passwordChangeRequired: value }),
124	}));

