 74	function resolvePresetDates(
 75	  preset: PeriodPreset,
 76	  customFrom: string,
 77	  customTo: string
 78	): { dateFrom: string | null; dateTo: string | null; label: string } {
 79	  const today = new Date();
 80	  const y = today.getFullYear();
 81	  const m = today.getMonth(); // 0-indexed
 82	
 83	  if (preset === 'this_month') {
 84	    const start = `${y}-${String(m + 1).padStart(2, '0')}-01`;
 85	    const end = new Date(y, m + 1, 0).toISOString().slice(0, 10);
 86	    return { dateFrom: start, dateTo: end, label: `Tháng ${m + 1}/${y}` };
 87	  }
 88	
 89	  if (preset === 'last_month') {
 90	    const d = new Date(y, m - 1, 1);
 91	    const ly = d.getFullYear();
 92	    const lm = d.getMonth();
 93	    const start = `${ly}-${String(lm + 1).padStart(2, '0')}-01`;
 94	    const end = new Date(ly, lm + 1, 0).toISOString().slice(0, 10);
 95	    return { dateFrom: start, dateTo: end, label: `Tháng ${lm + 1}/${ly}` };
 96	  }
 97	
 98	  if (preset === 'this_quarter') {
 99	    const q = Math.floor(m / 3);
100	    const startMonth = q * 3;
101	    const start = `${y}-${String(startMonth + 1).padStart(2, '0')}-01`;
102	    const end = new Date(y, startMonth + 3, 0).toISOString().slice(0, 10);
103	    return { dateFrom: start, dateTo: end, label: `Quý ${q + 1}/${y}` };
104	  }
105	
106	  if (preset === 'this_year') {
107	    return { dateFrom: `${y}-01-01`, dateTo: `${y}-12-31`, label: `Năm ${y}` };
108	  }
109	
110	  // custom
111	  const label =
112	    customFrom && customTo
113	      ? `${customFrom} → ${customTo}`
114	      : customFrom
115	        ? `Từ ${customFrom}`
116	        : customTo
117	          ? `Đến ${customTo}`
118	          : 'Tùy chọn';
119	  return { dateFrom: customFrom || null, dateTo: customTo || null, label };
120	}
