 24	    /**
 25	     * @param array<int, int|null> $deptIds
 26	     * @param array<int, int|null> $ownerUserIds
 27	     */
 28	    protected function isAllowedByDepartmentScope(InternalUser $user, array $deptIds = [], array $ownerUserIds = []): bool
 29	    {
 30	        $userId = (int) $user->getKey();
 31	        if ($this->accessService()->isAdmin($userId)) {
 32	            return true;
 33	        }
 34	
 35	        $allowedDeptIds = $this->accessService()->resolveDepartmentIdsForUser($userId);
 36	        if ($allowedDeptIds === null) {
 37	            return true;
 38	        }
 39	
 40	        $normalizedDeptIds = array_values(array_unique(array_map(
 41	            fn ($value): int => (int) $value,
 42	            array_filter($deptIds, fn ($value): bool => $value !== null && (int) $value > 0)
 43	        )));
 44	
 45	        if ($normalizedDeptIds !== [] && array_intersect($allowedDeptIds, $normalizedDeptIds) !== []) {
 46	            return true;
 47	        }
 48	
 49	        $normalizedOwnerIds = array_values(array_unique(array_map(
 50	            fn ($value): int => (int) $value,
 51	            array_filter($ownerUserIds, fn ($value): bool => $value !== null && (int) $value > 0)
 52	        )));
 53	
 54	        return in_array($userId, $normalizedOwnerIds, true);
 55	    }
