  9	class UserAccessService
 10	{
 11	    /**
 12	     * @return array<int, string>
 13	     */
 14	    public function roleCodesForUser(int $userId): array
 15	    {
 16	        if (! $this->hasTable('user_roles') || ! $this->hasTable('roles')) {
 17	            return [];
 18	        }
 19	
 20	        $now = now();
 21	
 22	        $roleIds = DB::table('user_roles')
 23	            ->where('user_id', $userId)
 24	            ->when($this->hasColumn('user_roles', 'is_active'), fn ($query) => $query->where('is_active', 1))
 25	            ->when(
 26	                $this->hasColumn('user_roles', 'expires_at'),
 27	                fn ($query) => $query->where(function ($builder) use ($now): void {
 28	                    $builder->whereNull('expires_at')->orWhere('expires_at', '>', $now);
 29	                })
 30	            )
 31	            ->pluck('role_id')
 32	            ->map(fn ($value): int => (int) $value)
 33	            ->all();
 34	
 35	        if ($roleIds === []) {
 36	            return [];
 37	        }
 38	
 39	        return DB::table('roles')
 40	            ->whereIn('id', $roleIds)
 41	            ->pluck('role_code')
 42	            ->map(fn ($value): string => strtoupper(trim((string) $value)))
 43	            ->filter(fn (string $value): bool => $value !== '')
 44	            ->values()
 45	            ->all();
 46	    }
 47	
 48	    public function isAdmin(int $userId): bool
 49	    {
 50	        return in_array('ADMIN', $this->roleCodesForUser($userId), true);
 51	    }
 52	
 53	    /**
 54	     * @return array<int, string>
 55	     */
 56	    public function permissionKeysForUser(int $userId): array
 57	    {
 58	        if ($this->isAdmin($userId)) {
 59	            return ['*'];
 60	        }
 61	
 62	        if (! $this->hasTable('permissions')) {
 63	            return [];
 64	        }
 65	
 66	        $now = now();
 67	
 68	        $rolePermissionKeys = [];
 69	        if ($this->hasTable('role_permission') && $this->hasTable('user_roles')) {
 70	            $rolePermissionKeys = DB::table('user_roles as ur')
 71	                ->join('role_permission as rp', 'ur.role_id', '=', 'rp.role_id')
 72	                ->join('permissions as p', 'rp.permission_id', '=', 'p.id')
 73	                ->where('ur.user_id', $userId)
 74	                ->when($this->hasColumn('user_roles', 'is_active'), fn ($query) => $query->where('ur.is_active', 1))
 75	                ->when(
 76	                    $this->hasColumn('user_roles', 'expires_at'),
 77	                    fn ($query) => $query->where(function ($builder) use ($now): void {
 78	                        $builder->whereNull('ur.expires_at')->orWhere('ur.expires_at', '>', $now);
 79	                    })
 80	                )
 81	                ->when($this->hasColumn('permissions', 'is_active'), fn ($query) => $query->where('p.is_active', 1))
 82	                ->pluck('p.perm_key')
 83	                ->map(fn ($value): string => trim((string) $value))
 84	                ->filter(fn (string $value): bool => $value !== '')
 85	                ->values()
 86	                ->all();
 87	        }
 88	
 89	        $grantedKeys = [];
 90	        $deniedKeys = [];
 91	        if ($this->hasTable('user_permissions')) {
 92	            $userPermissionRows = DB::table('user_permissions as up')
 93	                ->join('permissions as p', 'up.permission_id', '=', 'p.id')
 94	                ->where('up.user_id', $userId)
 95	                ->when(
 96	                    $this->hasColumn('user_permissions', 'expires_at'),
 97	                    fn ($query) => $query->where(function ($builder) use ($now): void {
 98	                        $builder->whereNull('up.expires_at')->orWhere('up.expires_at', '>', $now);
 99	                    })
100	                )
101	                ->when($this->hasColumn('permissions', 'is_active'), fn ($query) => $query->where('p.is_active', 1))
102	                ->select([
103	                    'p.perm_key',
104	                    DB::raw("UPPER(COALESCE(up.type, 'GRANT')) as override_type"),
105	                ])
106	                ->get();
107	
108	            foreach ($userPermissionRows as $row) {
109	                $permKey = trim((string) ($row->perm_key ?? ''));
110	                if ($permKey === '') {
111	                    continue;
112	                }
113	
114	                if (($row->override_type ?? 'GRANT') === 'DENY') {
115	                    $deniedKeys[] = $permKey;
116	                } else {
117	                    $grantedKeys[] = $permKey;
118	                }
119	            }
120	        }
121	
122	        $effective = array_values(array_unique(array_merge($rolePermissionKeys, $grantedKeys)));
123	        if ($deniedKeys !== []) {
124	            $deniedMap = array_fill_keys(array_values(array_unique($deniedKeys)), true);
125	            $effective = array_values(array_filter(
126	                $effective,
127	                fn (string $key): bool => ! isset($deniedMap[$key])
128	            ));
129	        }
130	
131	        return $effective;
132	    }
133	
134	    public function hasPermission(int $userId, string $permissionKey): bool
135	    {
136	        $permission = trim($permissionKey);
137	        if ($permission === '') {
138	            return false;
139	        }
140	
141	        $permissions = $this->permissionKeysForUser($userId);
142	        if (in_array('*', $permissions, true)) {
143	            return true;
144	        }
145	
146	        return in_array($permission, $permissions, true);
147	    }
