149	    /**
150	     * @return array<int, array{dept_id:int, scope_type:string}>
151	     */
152	    public function departmentScopesForUser(int $userId): array
153	    {
154	        if (! $this->hasTable('user_dept_scopes')) {
155	            return [];
156	        }
157	
158	        return DB::table('user_dept_scopes')
159	            ->where('user_id', $userId)
160	            ->select($this->selectColumns('user_dept_scopes', ['dept_id', 'scope_type']))
161	            ->get()
162	            ->map(function (object $row): array {
163	                return [
164	                    'dept_id' => (int) ($row->dept_id ?? 0),
165	                    'scope_type' => strtoupper(trim((string) ($row->scope_type ?? 'DEPT_ONLY'))),
166	                ];
167	            })
168	            ->filter(fn (array $row): bool => $row['dept_id'] > 0)
169	            ->values()
170	            ->all();
171	    }
172	
173	    /**
174	     * @return array{all:bool,self_only:bool,dept_ids:array<int, int>|null}
175	     */
176	    public function resolveEmployeeVisibility(int $userId): array
177	    {
178	        if ($this->isAdmin($userId)) {
179	            return [
180	                'all' => true,
181	                'self_only' => false,
182	                'dept_ids' => null,
183	            ];
184	        }
185	
186	        $scopes = $this->departmentScopesForUser($userId);
187	        if ($scopes === []) {
188	            return [
189	                'all' => false,
190	                'self_only' => true,
191	                'dept_ids' => [],
192	            ];
193	        }
194	
195	        $selfOnly = false;
196	        $deptIds = [];
197	
198	        foreach ($scopes as $scope) {
199	            if ($scope['scope_type'] === 'ALL') {
200	                return [
201	                    'all' => true,
202	                    'self_only' => false,
203	                    'dept_ids' => null,
204	                ];
205	            }
206	
207	            if ($scope['scope_type'] === 'SELF_ONLY') {
208	                $selfOnly = true;
209	                continue;
210	            }
211	
212	            if ($scope['scope_type'] === 'DEPT_AND_CHILDREN') {
213	                $deptIds = array_merge($deptIds, $this->expandDepartmentIds([$scope['dept_id']]));
214	                continue;
215	            }
216	
217	            $deptIds[] = $scope['dept_id'];
218	        }
219	
220	        $deptIds = array_values(array_unique(array_filter($deptIds, fn ($id): bool => (int) $id > 0)));
221	
222	        return [
223	            'all' => false,
224	            'self_only' => $selfOnly,
225	            'dept_ids' => $deptIds,
226	        ];
227	    }
228	
229	    /**
230	     * @return array<int, int>|null
231	     */
232	    public function resolveDepartmentIdsForUser(int $userId): ?array
233	    {
234	        $visibility = $this->resolveEmployeeVisibility($userId);
235	        if ($visibility['all']) {
236	            return null;
237	        }
238	
239	        $deptIds = $visibility['dept_ids'] ?? [];
240	        if ($visibility['self_only']) {
241	            $userDeptId = InternalUser::query()->where('id', $userId)->value('department_id');
242	            if ($userDeptId !== null) {
243	                $deptIds[] = (int) $userDeptId;
244	            }
245	        }
246	
247	        return array_values(array_unique(array_filter($deptIds, fn ($id): bool => (int) $id > 0)));
248	    }
249	
250	    /**
251	     * @param array<int, int> $rootDeptIds
252	     * @return array<int, int>
253	     */
254	    private function expandDepartmentIds(array $rootDeptIds): array
255	    {
256	        if (! $this->hasTable('departments') || ! $this->hasColumn('departments', 'id') || ! $this->hasColumn('departments', 'parent_id')) {
257	            return array_values(array_unique($rootDeptIds));
258	        }
259	
260	        $childrenByParent = DB::table('departments')
261	            ->select(['id', 'parent_id'])
262	            ->get()
263	            ->groupBy(fn (object $row): string => (string) ($row->parent_id ?? ''))
264	            ->map(fn ($rows) => $rows->pluck('id')->map(fn ($id): int => (int) $id)->all())
265	            ->all();
266	
267	        $visited = [];
268	        $queue = array_values(array_unique(array_filter($rootDeptIds, fn ($id): bool => (int) $id > 0)));
269	
270	        while ($queue !== []) {
271	            $current = array_shift($queue);
272	            if ($current === null || isset($visited[$current])) {
273	                continue;
274	            }
275	
276	            $visited[$current] = true;
277	            $children = $childrenByParent[(string) $current] ?? [];
278	            foreach ($children as $childId) {
279	                if (! isset($visited[$childId])) {
280	                    $queue[] = $childId;
281	                }
282	            }
283	        }
284	
285	        return array_map('intval', array_keys($visited));
286	    }
