 27	    public function authorizeMutationByScope(Request $request, string $resource, ?int $departmentId, ?int $ownerId = null): ?JsonResponse
 28	    {
 29	        $userId = $this->resolveAuthenticatedUserId($request);
 30	        if ($userId === null) {
 31	            return response()->json(['message' => 'Unauthorized.'], 401);
 32	        }
 33	
 34	        if ($this->userAccessService->isAdmin($userId)) {
 35	            return null;
 36	        }
 37	
 38	        if ($departmentId !== null) {
 39	            $allowedDepartmentIds = $this->userAccessService->resolveDepartmentIdsForUser($userId);
 40	            if ($allowedDepartmentIds === null || in_array($departmentId, $allowedDepartmentIds, true)) {
 41	                return null;
 42	            }
 43	
 44	            return $this->denyScopeMutation($resource);
 45	        }
 46	
 47	        if ($ownerId !== null && $ownerId === $userId) {
 48	            return null;
 49	        }
 50	
 51	        return $this->denyScopeMutation($resource);
 52	    }
