 46	
 47	    public function index(Request $request): JsonResponse
 48	    {
 49	        if (! $this->support->hasTable('receipts')) {
 50	            return $this->support->missingTable('receipts');
 51	        }
 52	
 53	        $query = Receipt::query()
 54	            ->select($this->support->selectColumns('receipts', [
 55	                'id', 'receipt_code', 'invoice_id', 'contract_id', 'customer_id',
 56	                'receipt_date', 'amount', 'payment_method', 'bank_name', 'bank_account',
 57	                'transaction_ref', 'status', 'is_reversed', 'is_reversal_offset',
 58	                'original_receipt_id', 'notes', 'confirmed_by', 'confirmed_at',
 59	                'created_at', 'created_by',
 60	            ]))
 61	            ->with([
 62	                'customer' => fn ($q) => $q->select($this->support->customerRelationColumns()),
 63	                'invoice'  => fn ($q) => $q->select(
 64	                    $this->support->selectColumns('invoices', ['id', 'invoice_code'])
 65	                ),
 66	                'contract' => fn ($q) => $q->select(
 67	                    $this->support->selectColumns('contracts', ['id', 'contract_code'])
 68	                ),
 69	            ]);
 70	
 71	        // Search
 72	        if ($q = $request->input('q')) {
 73	            $like = '%' . $q . '%';
 74	            $query->where(function (Builder $sub) use ($like) {
 75	                $sub->where('receipts.receipt_code', 'like', $like)
 76	                    ->orWhereHas('customer', fn ($c) => $c->where('customer_name', 'like', $like))
 77	                    ->orWhere('receipts.transaction_ref', 'like', $like);
 78	            });
 79	        }
 80	
 81	        // Filters
 82	        if ($invoiceId = $this->support->parseNullableInt($request->input('invoice_id'))) {
 83	            $query->where('receipts.invoice_id', $invoiceId);
 84	        }
 85	        if ($customerId = $this->support->parseNullableInt($request->input('customer_id'))) {
 86	            $query->where('receipts.customer_id', $customerId);
 87	        }
 88	        if ($method = $request->input('payment_method')) {
 89	            if (in_array($method, self::PAYMENT_METHODS, true)) {
 90	                $query->where('receipts.payment_method', $method);
 91	            }
 92	        }
 93	        // Date filters — validate format before binding
 94	        $request->validate([
 95	            'receipt_date_from' => ['nullable', 'date'],
 96	            'receipt_date_to'   => ['nullable', 'date'],
 97	        ]);
 98	
 99	        if ($from = $request->input('receipt_date_from')) {
100	            $query->where('receipts.receipt_date', '>=', $from);
101	        }
102	        if ($to = $request->input('receipt_date_to')) {
103	            $query->where('receipts.receipt_date', '<=', $to);
104	        }
105	
106	        // Sort + paginate
107	        $sortCol = $this->support->resolveSortColumn($request, self::SORT_MAP, 'receipt_date');
108	        $sortDir = $this->support->resolveSortDirection($request);
109	        $query->orderBy($sortCol, $sortDir)->orderBy('receipts.id', 'desc');
110	
111	        [$page, $perPage] = $this->support->resolvePaginationParams($request);
112	        $total = (clone $query)->count();
113	        $rows  = $query->forPage($page, $perPage)->get();
114	
115	        $data = $rows->map(fn (Receipt $r) => $this->serializeReceipt($r))->values();
116	
117	        return response()->json([
118	            'data' => $data,
119	            'meta' => $this->support->buildPaginationMeta($page, $perPage, $total),
120	        ]);
