 56	    public function statusCatalog(Request $request): JsonResponse
 57	    {
 58	        if (($missing = $this->missingTablesResponse()) !== null) {
 59	            return $missing;
 60	        }
 61	
 62	        $counts = DB::table('customer_request_cases')
 63	            ->select(['current_status_code', DB::raw('COUNT(*) as aggregate')])
 64	            ->whereNull('deleted_at')
 65	            ->groupBy('current_status_code')
 66	            ->pluck('aggregate', 'current_status_code');
 67	
 68	        $groups = [];
 69	        foreach (CustomerRequestCaseRegistry::all() as $definition) {
 70	            $statusCode = (string) $definition['status_code'];
 71	            $group = $this->statusGroups[$statusCode] ?? ['group_code' => 'statuses', 'group_label' => 'Trạng thái'];
 72	            $groupKey = $group['group_code'];
 73	            if (! isset($groups[$groupKey])) {
 74	                $groups[$groupKey] = [
 75	                    'group_code' => $group['group_code'],
 76	                    'group_label' => $group['group_label'],
 77	                    'processes' => [],
 78	                ];
 79	            }
 80	
 81	            $groups[$groupKey]['processes'][] = [
 82	                ...$this->serializeStatusMeta($definition),
 83	                'active_count' => (int) ($counts[$statusCode] ?? 0),
 84	            ];
 85	        }
 86	
 87	        return response()->json([
 88	            'data' => [
 89	                'master_fields' => CustomerRequestCaseRegistry::masterFields(),
 90	                'groups' => array_values($groups),
 91	                'statuses' => array_values(array_map(
 92	                    fn (array $definition): array => [
 93	                        ...$this->serializeStatusMeta($definition),
 94	                        'active_count' => (int) ($counts[$definition['status_code']] ?? 0),
 95	                    ],
 96	                    CustomerRequestCaseRegistry::catalog()
 97	                )),
 98	            ],
 99	        ]);
100	    }
